import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import toast from 'react-hot-toast';
import { leadsApi } from '../services/api';

const LeadsContext = createContext(null);

export function LeadsProvider({ children }) {
  const [leads, setLeads] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchLeads = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await leadsApi.getAll();
      setLeads(data);
    } catch (err) {
      setError(err.message);
      // Use mock data for demo if backend unreachable
      setLeads(MOCK_LEADS);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchStats = useCallback(async () => {
    try {
      const data = await leadsApi.getStats();
      setStats(data);
    } catch {
      // derive from leads
    }
  }, []);

  useEffect(() => {
    fetchLeads();
    fetchStats();
  }, [fetchLeads, fetchStats]);

  const createLead = useCallback(async (formData) => {
    const tid = toast.loading('Creating lead...');
    try {
      const newLead = await leadsApi.create(formData);
      setLeads((prev) => [newLead, ...prev]);
      toast.success('Lead created successfully!', { id: tid });
      return newLead;
    } catch (err) {
      // Demo mode: create locally
      // const mockLead = { ...formData, id: Date.now(), pipelineStatus: 'NEW', score: Math.floor(Math.random() * 45 + 50), createdAt: new Date().toISOString(), source: formData.source || 'Website' };
      setLeads((prev) => [mockLead, ...prev]);
      toast.success('Lead created (demo mode)', { id: tid });
      return mockLead;
    }
  }, []);

  const updateLeadStatus = useCallback(async (id, status) => {
    const prev = leads.find((l) => l.id === id);
    // Optimistic update
    setLeads((ls) => ls.map((l) => (l.id === id ? { ...l, pipelineStatus: status } : l)));
    try {
      await leadsApi.updateStatus(id, status);
    } catch {
      // Rollback
      if (prev) setLeads((ls) => ls.map((l) => (l.id === id ? prev : l)));
      toast.error('Failed to update status');
    }
  }, [leads]);

  const analyzeLead = useCallback(async (id) => {
    const tid = toast.loading('Running AI analysis…');
    try {
      const updated = await leadsApi.analyze(id);
      setLeads((ls) => ls.map((l) => (l.id === id ? updated : l)));
      toast.success('Analysis complete!', { id: tid });
      return updated;
    } catch {
      toast.error('Failed to analyze lead', { id: tid });
      throw new Error('Analysis failed');
    }
  }, []);

  const generateReply = useCallback(async (id) => {
    const tid = toast.loading('Generating AI reply…');
    try {
      const updated = await leadsApi.generateReply(id);
      setLeads((ls) => ls.map((l) => (l.id === id ? updated : l)));
      toast.success('Reply generated!', { id: tid });
      return updated;
    } catch {
      toast.error('Failed to generate reply', { id: tid });
      throw new Error('Reply failed');
    }
  }, []);

  const deleteLead = useCallback(async (id) => {
    setLeads((ls) => ls.filter((l) => l.id !== id));
    try {
      await leadsApi.delete(id);
      toast.success('Lead deleted');
    } catch {
      toast.error('Delete failed');
    }
  }, []);

  // Computed stats from leads when API stats unavailable
  const computedStats = stats || {
    totalLeads: leads.length,
    newLeads: leads.filter((l) => l.pipelineStatus === 'NEW').length,
    qualifiedLeads: leads.filter((l) => l.pipelineStatus === 'QUALIFIED').length,
    wonLeads: leads.filter((l) => l.pipelineStatus === 'WON').length,
    lostLeads: leads.filter((l) => l.pipelineStatus === 'LOST').length,
    avgScore: leads.length ? Math.round(leads.reduce((s, l) => s + (l.score || 0), 0) / leads.length) : 0,
    hotLeads: leads.filter((l) => (l.score || 0) >= 80).length,
  };

  return (
    <LeadsContext.Provider value={{ leads, stats: computedStats, loading, error, fetchLeads, createLead, updateLeadStatus, analyzeLead, generateReply, deleteLead }}>
      {children}
    </LeadsContext.Provider>
  );
}

export function useLeads() {
  const ctx = useContext(LeadsContext);
  if (!ctx) throw new Error('useLeads must be inside LeadsProvider');
  return ctx;
}

